query:
PREFIX kgo: <http://github.com/ScaDS/kgpipe/ontology/>
CONSTRUCT { ?impl ?p ?o }
WHERE {
  ?impl a kgo:Implementation ;
        ?p ?o .
} LIMIT 60

PREFIX kgo: <http://github.com/ScaDS/kgpipe/ontology/>
PREFIX kgr: <http://github.com/ScaDS/kgpipe/resource/>
CONSTRUCT { ?impl kgo:usesTool ?tool }
WHERE {
  ?impl a kgo:Implementation ;
        kgo:usesTool ?tool .
} LIMIT 80

PREFIX kgo: <http://github.com/ScaDS/kgpipe/ontology/>
CONSTRUCT { ?impl kgo:implementsMethod ?method }
WHERE {
  ?impl a kgo:Implementation ;
        kgo:implementsMethod ?method .
} LIMIT 80

PREFIX kgo: <http://github.com/ScaDS/kgpipe/>
CONSTRUCT { ?impl kgo:config_spec ?spec . ?spec kgo:hasParameter ?param . ?param ?pp ?po }
WHERE {
  ?impl a kgo:Implementation ;
        kgo:config_spec ?spec .
  ?spec kgo:hasParameter ?param .
  OPTIONAL { ?param ?pp ?po . }
} LIMIT 120

PREFIX kgo: <http://github.com/ScaDS/kgpipe/ontology/>
CONSTRUCT { ?impl ?rel ?format }
WHERE {
  ?impl a kgo:Implementation .
  { ?impl kgo:hasInput ?format . BIND(kgo:hasInput AS ?rel) }
  UNION
  { ?impl kgo:hasOutput ?format . BIND(kgo:hasOutput AS ?rel) }
} LIMIT 100

PREFIX kgo: <http://github.com/ScaDS/kgpipe/ontology/>
CONSTRUCT { ?impl ?p ?o }
WHERE {
  ?impl a kgo:Implementation ; ?p ?o .
} LIMIT 30
